const MAX_APP_VERSION_FOR_RANGE = 99999999;

// --- Helper Functions for Parsing and Overlap Checks ---

/**
 * Parses an appVersion string into a standardized object for overlap checks.
 * This function converts various appVersion formats (e.g., ">:1400", "1399-1405", "1400", "NA")
 * into a uniform representation, either as a numerical range [min, max] or an 'all' type.
 *
 * @param {string} versionString - The appVersion string from a condition object.
 * @returns {{type: 'all'} | {type: 'range', min: number, max: number}}
 * @throws {Error} If an unsupported appVersion format is encountered, indicating a data issue.
 */
function parseAppVersion(versionString) {
  if (versionString === "NA") {
    return { type: "all" }; // Represents "all versions"
  }

  // Matches for ">:VALUE" (e.g., ">:1400")
  const gtMatch = versionString.match(/^>:(\d+)$/);
  if (gtMatch) {
    // For ">:X", the range starts from X + 1 up to MAX_APP_VERSION_FOR_RANGE.
    // parseInt(gtMatch[1], 10) ensures base-10 parsing.
    return {
      type: "range",
      min: parseInt(gtMatch[1], 10) + 1,
      max: MAX_APP_VERSION_FOR_RANGE,
    };
  }

  // Matches for "<:VALUE" (e.g., "<:1400")
  const ltMatch = versionString.match(/^<:(\d+)$/);
  if (ltMatch) {
    // For "<:X", the range goes from 0 up to X - 1.
    // Assuming app versions are non-negative integers.
    return { type: "range", min: 0, max: parseInt(ltMatch[1], 10) - 1 };
  }

  // Matches for "MIN-MAX" (e.g., "1399-1405")
  const rangeMatch = versionString.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    return {
      type: "range",
      min: parseInt(rangeMatch[1], 10),
      max: parseInt(rangeMatch[2], 10),
    };
  }

  // Matches for "VALUE" (e.g., "1400" for "==" operator)
  const eqMatch = versionString.match(/^(\d+)$/);
  if (eqMatch) {
    // For "VALUE", the range is a single point.
    return {
      type: "range",
      min: parseInt(eqMatch[1], 10),
      max: parseInt(eqMatch[1], 10),
    };
  }

  // If none of the above formats match, it's an unexpected or invalid format.
  // This could indicate a problem with how the condition strings are being generated/stored.
  throw new Error(
    `Invalid appVersion format encountered: '${versionString}'. Please check data consistency.`
  );
}

/**
 * Checks for overlap between two parsed appVersion objects.
 * Overlap exists if their numerical ranges intersect, or if either represents "all versions".
 *
 * @param {{type: 'all'} | {type: 'range', min: number, max: number}} v1 - Parsed appVersion object 1.
 * @param {{type: 'all'} | {type: 'range', min: number, max: number}} v2 - Parsed appVersion object 2.
 * @returns {boolean} True if the app versions overlap, false otherwise.
 */
function checkVersionOverlap(v1, v2) {
  // If either version specifies "all" (i.e., 'NA' input), it implicitly overlaps with any other version.
  if (v1.type === "all" || v2.type === "all") {
    return true;
  }

  // Both are 'range' types. Check if their closed numerical ranges intersect.
  // Intersection occurs if (start1 <= end2) AND (start2 <= end1).
  return v1.min <= v2.max && v2.min <= v1.max;
}

/**
 * Parses a cityIds string into a standardized object for overlap checks.
 * Converts "NA" or empty string to an 'all' type, otherwise to a Set of numbers.
 *
 * @param {string} cityIdsString - The cityIds string (e.g., "NA", "1,2,3").
 * @returns {{type: 'all'} | {type: 'set', ids: Set<number>}}
 */
function parseCityIds(cityIdsString) {
  // An empty string for cityIds also gets converted to 'NA' in the condition object by your existing code.
  if (cityIdsString === "NA" || cityIdsString === "") {
    return { type: "all" }; // Represents "all city IDs"
  }
  // Split the string by commas, trim whitespace from each part, parse to integer,
  // and filter out any non-numeric results (e.g., from extra commas or malformed parts).
  const ids = new Set(
    cityIdsString
      .split(",")
      .map((id) => parseInt(id.trim(), 10))
      .filter((id) => !isNaN(id))
  );
  return { type: "set", ids: ids };
}

/**
 * Checks for overlap between two parsed cityIds objects.
 * Overlap exists if their sets have common elements, or if either represents "all city IDs".
 *
 * @param {{type: 'all'} | {type: 'set', ids: Set<number>}} c1 - Parsed cityIds object 1.
 * @param {{type: 'all'} | {type: 'set', ids: Set<number>}} c2 - Parsed cityIds object 2.
 * @returns {boolean} True if the city IDs overlap, false otherwise.
 */
function checkCityIdOverlap(c1, c2) {
  // If either city ID specifies "all" (i.e., 'NA' input or empty string), it implicitly overlaps with any other.
  if (c1.type === "all" || c2.type === "all") {
    return true;
  }

  // Both are 'set' types. Check if their sets have any common elements (intersection).
  for (const id of c1.ids) {
    if (c2.ids.has(id)) {
      return true; // Found at least one common city ID, so they overlap.
    }
  }
  return false; // No common city IDs found, no overlap.
}

/**
 * Checks for overlap between two appChannel strings.
 * Overlap exists if they are identical, or if either represents "any app type" ('NA').
 *
 * @param {string} type1 - AppChannel string 1.
 * @param {string} type2 - AppChannel string 2.
 * @returns {boolean} True if the app types overlap, false otherwise.
 */
function checkAppChannelOverlap(type1, type2) {
  // Your code converts an empty appChannel input to 'NA'.
  // This implies 'NA' represents "any app type" or a global configuration.
  // Therefore, 'NA' should overlap with any specific app type, and with 'NA' itself.
  if (type1 === "NA" || type2 === "NA") {
    return true;
  }
  // Otherwise, if both are specific app types, they must be identical to overlap.
  return type1 === type2;
}

/**
 * Main validation function to check if a new condition overlaps with any existing conditions.
 * An overlap is considered if there's a match across appChannel, cityIds, AND appVersion.
 *
 * @param {object} newConditionData - The newly formed condition object (e.g., { cityIds: "1", appChannel: "snacc", appVersion: "1399-1400", configValue: "ABC" }).
 * @param {Array<object>} existingConditions - The current array of conditions from `addAppConfigCondition.value`.
 * @returns {boolean} True if NO overlap is found with any existing condition, false if an overlap IS found.
 */
function validateNoOverlap(newConditionData, existingConditions) {
  let parsedNewAppVersion;
  let shouldCheckAppVersion = true;
  try {
    parsedNewAppVersion = parseAppVersion(newConditionData.appVersion);
  } catch (error) {
    shouldCheckAppVersion = false;
    return -2; // Block due to malformed new appVersion string.
  }

  const parsedNewCityIds = parseCityIds(newConditionData.cityIds);
  const newAppChannel = newConditionData.appChannel;

  for (let index = 0; index < existingConditions.length; index++) {
    let parsedExistingAppVersion;
    try {
      parsedExistingAppVersion = parseAppVersion(
        existingConditions[index].appVersion
      );
    } catch (error) {
      console.warn(
        `Skipping overlap check for malformed existing appVersion '${existingConditions[index].appVersion}': ${error.message}`
      );
      shouldCheckAppVersion = false; // Skip this malformed existing entry and check the next one.
    }

    const parsedExistingCityIds = parseCityIds(
      existingConditions[index].cityIds
    );
    const existingAppChannel = existingConditions[index].appChannel;

    const appChannelOverlaps = checkAppChannelOverlap(
      newAppChannel,
      existingAppChannel
    );
    const cityIdsOverlaps = checkCityIdOverlap(
      parsedNewCityIds,
      parsedExistingCityIds
    );
    let appVersionOverlaps = true;
    if (shouldCheckAppVersion) {
      appVersionOverlaps = checkVersionOverlap(parsedNewAppVersion, parsedExistingAppVersion);
    }
    if (appChannelOverlaps && cityIdsOverlaps) {
      if (!shouldCheckAppVersion || appVersionOverlaps) {
        return Number(index); // Overlap detected, validation fails.
      }
    }
  }

  return Number(-1); // No overlap found with any existing condition.
}

